image.asymptote:
// 3-D interactive (WebGL) figure.
import graph3;
size(8.5cm);
currentprojection=orthographic(5,3,2.4);
real a=2;
path3 helix=graph(new triple(real t){return (a*cos(t), a*sin(t), 1+t/4);}, 0, 4pi, 220, operator ..);
draw(helix, blue+linewidth(1.1pt));
draw(circle((0,0,0), a, (0,0,1)), gray(0.6)+dashed);
dot((0,0,0), yellow+8pt); label("porch light", (0,0,0), 3*S);
real t0=1.7; triple Q=(a*cos(t0), a*sin(t0), 1+t0/4);
draw((0,0,0)--Q, black+linewidth(1.3pt), Arrow3); label("$\mathbf r(t)$", 0.6*Q, NW);
dot((a,0,1)); label("$t=0$", (a,0,1), 2*E);
draw(O--(3,0,0),gray,Arrow3); draw(O--(0,3,0),gray,Arrow3); draw(O--(0,0,4.6),gray,Arrow3);
label("$x$",(3,0,0),S); label("$y$",(0,3,0),E); label("$z$",(0,0,4.6),N);
